sql:
SELECT gender, name, LAG(gender) OVER (ORDER BY customer_id) AS previous_gender
FROM customers
WHERE customer_id > 5;

external_knowledge:
- "anchors of the ship" refers to customers who have completed their orders;
- "carrying the banner of loyalty" refers to participating in loyalty programs;
- "navigated the waters" means the orders have reached the "delivered" status;
- "holding a map to uncharted treasure that hasn't been claimed yet" signifies having store credits that have not yet expired.

- "shining stars" are metaphors for the customers;
- "treasure chests" are a metaphor for store credits;
- "vast sea of store credits" implies the extensive collection of store credits in the database.

sql:
SELECT customer_id, SUM(points) AS total_reward_points
FROM reward_points
GROUP BY customer_id;

SELECT AVG(points) AS average_reward_points
FROM reward_points
WHERE status = 'active';

SELECT AVG(points)
FROM reward_points
WHERE points > 500 AND website_id = 0;

SELECT DISTINCT customers.name, customers.email
FROM customers
JOIN reward_points ON customers.customer_id = reward_points.customer_id;

SELECT c.customer_id, c.name
FROM customers c
INNER JOIN customer_websites cw ON c.customer_id = cw.customer_id;

SELECT websites.website_name, reward_points.points
FROM websites
INNER JOIN reward_points ON websites.website_id = reward_points.website_id;
